      "https://www.flickr.com/photos/maxwellstoreydubler/7158337145/sizes/l/in/photostream",
      "https://www.flickr.com/photos/maxwellstoreydubler/7158337375/sizes/c/in/photostream",
      "https://www.flickr.com/photos/maxwellstoreydubler/7158339609/sizes/c/in/photostream",
      "https://www.flickr.com/photos/maxwellstoreydubler/7343540488/sizes/c/in/photostream",
      "https://www.flickr.com/photos/maxwellstoreydubler/7343545390/sizes/c/in/photostream",
      "https://www.flickr.com/photos/maxwellstoreydubler/7158344159/sizes/c/in/photostream",
      "https://www.flickr.com/photos/maxwellstoreydubler/7158335107/sizes/h/in/photostream",
      "https://www.flickr.com/photos/maxwellstoreydubler/7343545190/sizes/c/in/photostream",
      "https://www.flickr.com/photos/maxwellstoreydubler/7158337847/sizes/c/in/photostream",
